BasePathManager = class("BasePathManager")

function BasePathManager:ctor(pathId, processId)
    local config = PathConfig:getConfigById(pathId)
    self.processId = processId
    self.canPlaceBlockIds = config.blockIds
    self.canPlaceArea = config.area
    self.startYaw = config.startYaw
    self.Id = config.ID
    self.startPos = config.startPos
    self.endPos = config.endPos
    self.isRunning = false
    self.protectUserId = {}
    self.monsters = {}
    self.playerSpawnPos = config.spawnPos
    self.playerSpawnYaw = config.spawnYaw
    self.pathMissNum = 0
    self.TimerKey = LuaTimer:scheduleTimer(function()
        self:onTick()
    end, Define.PathManagerTickPeriod)
end

function BasePathManager:addPlayer(player)
    table.insert(self.protectUserId, player.userId)
    player.canPlaceArea = self.canPlaceArea
end

function BasePathManager:subPlayer(player)
    for index, userId in pairs(self.protectUserId) do
        if userId == player.userId then
            table.remove(self.protectUserId, index)
        end
    end
end

function BasePathManager:onTick()
    for _, monster in pairs(self.monsters) do
        monster:onTick()
    end
    table.sort(self.monsters, function(a, b)
        return a.progress > b.progress
    end)
end

function BasePathManager:addMonster(monster)
    table.insert(self.monsters, monster)
    LuaEntityManager:addEntity(monster)
end

function BasePathManager:subMonster(entityId)
    for index, value in pairs(self.monsters) do
        if value.entityId == entityId then
            table.remove(self.monsters, index)
            LuaEntityManager:subEntity(entityId)
            break
        end
    end
    if self.count == 0 and #self.monsters == 0 then
        self.isRunning = false
    end
end

function BasePathManager:getNextTarget(monster, hadAttackList)
    local function getMonsterIndex(monster)
        for index, m in pairs(self.monsters) do
            if monster.entityId == m.entityId then
                return index
            end
        end
        return 0
    end
    local index = getMonsterIndex(monster)
    local before, after
    for i = index - 1, 1, -1 do
        if self.monsters[i].futureHp > 0 then
            before = self.monsters[i]
            break
        end
    end

    for i = index + 1, #self.monsters do
        if self.monsters[i].futureHp > 0 then
            after = self.monsters[i]
            break
        end
    end
    if before and after then
        if math.abs(monster.progress - before.progress) * 1.5 < math.abs(monster.progress - after.progress) then
            return before
        elseif math.abs(monster.progress - before.progress) > math.abs(monster.progress - after.progress) * 1.5 then
            return after
        end
        if (hadAttackList[tostring(before.entityId)] or 0) < (hadAttackList[tostring(after.entityId)] or 0) then
            return before
        else
            return after
        end
    end
    return before or after
end

function BasePathManager:onDestroy()
    LuaTimer:cancel(self.TimerKey)
    self.count = 0
    self.monsters = {}
end